const fs = require('fs');
const path = require('path');

const inputFolder = $input.first().json.input_folder;
const outputFolder = $input.first().json.output_folder;

if (!fs.existsSync(outputFolder)) {
  fs.mkdirSync(outputFolder, { recursive: true });
}

const exts = ['.xls', '.xlsm', '.xlsb', '.csv'];
let files;
try {
  files = fs.readdirSync(inputFolder)
    .filter(f => exts.includes(path.extname(f).toLowerCase()))
    .map(f => ({
      filename: f,
      filepath: path.join(inputFolder, f),
      output_folder: outputFolder
    }));
} catch (e) {
  throw new Error('No se puede leer la carpeta: ' + inputFolder + '. ' + e.message);
}

if (files.length === 0) {
  throw new Error('Sin archivos .xls/.xlsm/.xlsb/.csv en: ' + inputFolder);
}

return files.map(f => ({ json: f }));

const XLSX = require('xlsx');
const path = require('path');

const item = $input.item.json;
const t0 = Date.now();

try {
  const wb = XLSX.readFile(item.filepath);
  const basename = path.basename(item.filename, path.extname(item.filename));
  const outputPath = path.join(item.output_folder, basename + '.xlsx');
  XLSX.writeFile(wb, outputPath, { bookType: 'xlsx' });
  return {
    json: {
      filename: item.filename,
      output: basename + '.xlsx',
      output_folder: item.output_folder,
      status: 'ok',
      hojas: wb.SheetNames.length,
      nombres_hojas: wb.SheetNames.join(', '),
      tiempo_ms: Date.now() - t0
    }
  };
} catch (err) {
  return {
    json: {
      filename: item.filename,
      output: '',
      output_folder: item.output_folder,
      status: 'error',
      hojas: 0,
      nombres_hojas: '',
      error: err.message,
      tiempo_ms: Date.now() - t0
    }
  };
}

const fs = require('fs');
const path = require('path');

const items = $input.all();
const ok = items.filter(i => i.json.status === 'ok');
const errors = items.filter(i => i.json.status === 'error');

const header = 'archivo_origen,archivo_salida,estado,hojas,nombres_hojas,tiempo_ms,error';
const rows = items.map(i => {
  const j = i.json;
  return [
    '"' + j.filename + '"',
    '"' + (j.output || '') + '"',
    j.status,
    j.hojas,
    '"' + (j.nombres_hojas || '') + '"',
    j.tiempo_ms,
    '"' + (j.error || '') + '"'
  ].join(',');
});

const csv = [header, ...rows].join('\n');
const outputFolder = items[0]?.json?.output_folder || '/data/conversion/output';
const fecha = new Date().toISOString().slice(0, 10);
const reportPath = path.join(outputFolder, 'REPORTE_' + fecha + '.csv');
fs.writeFileSync(reportPath, csv, 'utf8');

return [{
  json: {
    total: items.length,
    convertidos: ok.length,
    errores: errors.length,
    reporte: reportPath,
    mensaje: ok.length + '/' + items.length + ' archivos convertidos a .xlsx',
    detalle_errores: errors.map(e => ({ archivo: e.json.filename, error: e.json.error }))
  }
}];
